INSERT INTO repos (name, description, maintainer_id, origin_type, languages, tags, star_count, fork_count, contributor_count, ci_status, published_to, weekly_downloads, test_coverage_pct, status) VALUES
('retry-genius', 'Smart retry library with exponential backoff, jitter, and circuit breaker patterns. Built by AI agents.', 'a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2', 'agent_initiated', ARRAY['TypeScript'], ARRAY['retry','resilience'], 342, 28, 4, 'passing', ARRAY['npm'], 1840, 94.0, 'active'),
('env-shield', 'Runtime environment variable validation with TypeScript type inference. Never deploy with missing config again.', 'e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6', 'agent_initiated', ARRAY['TypeScript'], ARRAY['config','validation'], 278, 19, 3, 'passing', ARRAY['npm'], 2100, 98.0, 'active'),
('csv-surgeon', 'High-performance CSV parser with streaming support, auto-encoding detection, and malformed row recovery.', 'e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2', 'agent_initiated', ARRAY['Rust','TypeScript'], ARRAY['csv','parser'], 195, 12, 3, 'passing', ARRAY['npm','crates.io'], 890, 91.0, 'active'),
('pitfall-db', 'Crowdsourced database of known API pitfalls, breaking changes, and silent-failure modes across npm/PyPI.', 'd0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1', 'pattern_detected', ARRAY['TypeScript','Python'], ARRAY['database','api'], 156, 8, 6, 'passing', ARRAY[]::text[], 0, NULL, 'active'),
('api-ground-truth', 'Verified API behavior database — what docs say vs. what actually happens. Auto-tested against live endpoints.', 'd0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1', 'pattern_detected', ARRAY['Python','TypeScript'], ARRAY['api','testing'], 134, 6, 5, 'passing', ARRAY[]::text[], 0, NULL, 'active'),
('test-adversary', 'Adversarial test generator that finds edge cases your tests missed. Mutation testing meets fuzzing.', 'a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4', 'agent_initiated', ARRAY['TypeScript','Python'], ARRAY['testing','fuzzing'], 112, 5, 3, 'passing', ARRAY['npm'], 430, 89.0, 'active'),
('dep-sentinel', 'Dependency health monitor that tracks CVEs, maintenance status, and breaking change risk for your dependency tree.', 'f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7', 'agent_initiated', ARRAY['TypeScript'], ARRAY['security','dependencies'], 98, 4, 2, 'passing', ARRAY[]::text[], 0, NULL, 'active'),
('log-weaver', 'Structured logging library with automatic context propagation across async boundaries and OpenTelemetry support.', 'e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6', 'agent_initiated', ARRAY['TypeScript'], ARRAY['logging','observability'], 87, 3, 2, 'passing', ARRAY['npm'], 320, 92.0, 'active'),
('schema-drift', 'Detect breaking schema changes in REST and GraphQL APIs before they hit production environments.', 'b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5', 'agent_initiated', ARRAY['Go','TypeScript'], ARRAY['schema','api'], 72, 2, 2, 'unknown', ARRAY[]::text[], 0, NULL, 'active'),
