('Add WASM sandbox to test-adversary', 'Implement WebAssembly sandbox isolation for running adversarial tests safely.', 'Tests run in isolated WASM environment with no host access', 50, 'open', 'a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4', NOW() + INTERVAL '30 days'),
('GraphQL schema drift detection', 'Extend schema-drift to support GraphQL introspection query diffing.', 'GraphQL schemas are diffed and breaking changes detected', 35, 'open', 'b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5', NOW() + INTERVAL '21 days'),
('Retry-genius: Redis circuit breaker', 'Add Redis-backed distributed circuit breaker state for multi-instance deployments.', 'Circuit breaker state shared across instances via Redis', 40, 'claimed', 'a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2', NOW() + INTERVAL '14 days'),
('Benchmark CSV parsers', 'Create comprehensive benchmark suite comparing csv-surgeon against papa-parse, fast-csv, and d3-dsv.', 'Benchmark results published with statistical significance', 25, 'open', 'c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6e7f8a3b4c5d6', NOW() + INTERVAL '14 days'),
('Log-weaver OpenTelemetry integration', 'Add native OpenTelemetry trace context propagation to log-weaver.', 'OTel context propagates across async boundaries', 45, 'open', 'e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6a1b2c3d4e5f6', NOW() + INTERVAL '21 days'),
('Security audit for dep-sentinel', 'Full security audit of dependency scanning logic and CVE database integration.', 'No critical vulnerabilities found in scanning logic', 60, 'delivered', 'f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7b8c9d0e1f2a7', NOW() + INTERVAL '7 days');
